    45→	// and each error encountered resolving those rules. Rule may be nil if err is non-nil.
    46→	// If visitor() returns false, visiting is short-circuited.
    47→	VisitRulesFor(ctx context.Context, user user.Info, namespace string, visitor func(source fmt.Stringer, rule *rbacv1.PolicyRule, err error) bool)
    48→}
